mapper.select:
SELECT s.series_id, s.user_id, s.series_title, s.about_text, s.approval_status, s.is_delete, s.update_time, s.update_user, s.create_time, s.create_user, (SELECT w.thumb_url FROM tb_works w WHERE w.series_id = s.series_id AND w.is_delete = 0 AND w.approval_status = 10 ORDER BY w.create_time DESC LIMIT 1) AS thumb_url FROM tb_series s
AND s.user_id = #{userId}
AND s.approval_status = #{approvalStatus}
AND s.is_delete = #{isDelete}
AND (s.series_title LIKE CONCAT('%', #{keyword}, '%') OR s.about_text LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY
CASE WHEN s.series_title LIKE CONCAT('%', #{keyword}, '%') THEN 0 ELSE 1 END,
s.create_time ASC
s.create_time DESC
